const required = ['META_ACCESS_TOKEN'];
const missing = required.filter((key) => !process.env[key]);
if (missing.length) {
  throw new Error(`Missing environment variables: ${missing.join(', ')}`);
}
return [{ json: {
  access_token: process.env.META_ACCESS_TOKEN,
  business_id: process.env.META_BUSINESS_ID || '',
  graph_api_version: process.env.GRAPH_API_VERSION || 'v25.0',
  graph_base: `https://graph.facebook.com/${process.env.GRAPH_API_VERSION || 'v25.0'}`
}}];

const env = $('Load Env').first().json;
const businesses = $json.data || [];
const selected = env.business_id
  ? (businesses.find((b) => b.id === env.business_id) || { id: env.business_id, name: 'Provided Business ID' })
  : businesses[0];
if (!selected?.id) {
  throw new Error('No Business ID found. Provide META_BUSINESS_ID or fix token permissions for /me/businesses.');
}
return [{ json: { ...env, business: selected, available_businesses: businesses } }];

function normalizeText(value) {
  return String(value || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, ' ').trim();
}
function guessBrand(...values) {
  const text = normalizeText(values.filter(Boolean).join(' '));
  const rules = [
    { brand_id: 'kmediafilms', patterns: ['kmedia', 'k media', 'kmediafilms', 'k media films'] },
    { brand_id: 'en-la-galeria-de-ana', patterns: ['galeria de ana', 'en la galeria de ana', 'galeria ana', 'ana'] },
    { brand_id: 'drivip', patterns: ['drivip', 'dri vip', 'driveip'] }
  ];
  const matches = rules.filter((rule) => rule.patterns.some((pattern) => text.includes(normalizeText(pattern))));
  return matches.length === 1 ? matches[0].brand_id : 'needs_review';
}
const selected = $('Select Business').first().json;
const ownedPages = $('Get Owned Pages').first().json.data || [];
const clientPages = $('Get Client Pages').first().json.data || [];
const ownedAdAccounts = $('Get Owned Ad Accounts').first().json.data || [];
const clientAdAccounts = $('Get Client Ad Accounts').first().json.data || [];
const pages = [
  ...ownedPages.map((p) => ({ ...p, source: 'owned_pages' })),
  ...clientPages.map((p) => ({ ...p, source: 'client_pages' }))
].map((p) => ({
  page_id: p.id || '',
  page_name: p.name || '',
  username: p.username || '',
  link: p.link || '',
  instagram_business_id: '',
  source: p.source,
  matched_brand_guess: guessBrand(p.name, p.username, p.link)
}));
const ad_accounts = [
  ...ownedAdAccounts.map((a) => ({ ...a, source: 'owned_ad_accounts' })),
  ...clientAdAccounts.map((a) => ({ ...a, source: 'client_ad_accounts' }))
].map((a) => ({
  ad_account_id: a.id || (a.account_id ? `act_${a.account_id}` : ''),
  account_id: a.account_id || String(a.id || '').replace(/^act_/, ''),
  name: a.name || '',
  status: String(a.account_status || ''),
  currency: a.currency || '',
  timezone_name: a.timezone_name || '',
  source: a.source,
  matched_brand_guess: guessBrand(a.name, a.id, a.account_id)
}));
const brandNames = { kmediafilms: 'KMediaFilms', 'en-la-galeria-de-ana': 'En la Galería de Ana', drivip: 'DRIVIP' };
const brand_config_suggestions = Object.keys(brandNames).map((brand_id) => {
  const page = pages.find((item) => item.matched_brand_guess === brand_id) || {};
  const ad = ad_accounts.find((item) => item.matched_brand_guess === brand_id) || {};
  return {
    brand_id,
    brand_name: brandNames[brand_id],
    facebook_page_id: page.page_id || '',
    instagram_business_id: page.instagram_business_id || '',
    meta_ad_account_id: ad.ad_account_id || ''
  };
});
return [{ json: {
  business: selected.business,
  available_businesses: selected.available_businesses,
  pages,
  ad_accounts,
  brand_config_suggestions,
  warnings: [
    'This workflow does not enrich instagram_business_id per Page. Use scripts/meta-discover-assets.js for full enrichment.',
    'Review all matched_brand_guess values manually.',
    'No messages or ad changes were made.'
  ]
}}];
